#!/usr/bin/env node

/**
 * Minimal token extraction:
 * - Relies on com.figma.codeSyntax.WEB for variable names
 * - Emits per-file CSS to dist/tokens/css/*.tokens.css
 */

const fs = require("fs");
const path = require("path");
const fg = require("fast-glob");
const { parse } = require("jsonc-parser");

const REPO_ROOT = path.resolve(__dirname, "..");
const EXPORTS_DIR = path.join(REPO_ROOT, "figma", "exports");
const OUTPUT_DIR = path.join(REPO_ROOT, "dist", "tokens", "css");

const EXPORT_PATTERNS = [
  "figma/exports/**/*.token.json",
  "figma/exports/**/*.tokens.json",
  "figma/exports/**/*.token.jsonc",
  "figma/exports/**/*.tokens.jsonc",
];

function stripBom(text) {
  return text.charCodeAt(0) === 0xfeff ? text.slice(1) : text;
}

function readJsonLike(filePath) {
  const text = stripBom(fs.readFileSync(filePath, "utf8"));
  const errors = [];
  const data = parse(text, errors, {
    allowTrailingComma: true,
    disallowComments: false,
  });

  if (errors.length > 0) {
    const first = errors[0];
    throw new Error(
      `Failed to parse ${filePath} (offset ${first.offset}, length ${first.length}, code ${first.error})`,
    );
  }

  return data;
}

function normalizeOutputBase(filePath) {
  const base = path.basename(filePath).toLowerCase().replace(/\s+/g, "-");
  return base.replace(/\.jsonc?$/i, "");
}

function normalizePerFileBase(base) {
  if (base === "light-mode.tokens") return "color.light.tokens";
  if (base === "dark-mode.tokens") return "color.dark.tokens";
  if (base === "color-light.tokens") return "color.light.tokens";
  if (base === "color-dark.tokens") return "color.dark.tokens";
  return base;
}

function collectTokens(node, pathSegments = [], list = []) {
  if (!node || typeof node !== "object") return list;
  if (node.$value !== undefined) {
    list.push({
      pathSegments,
      type: node.$type,
      value: node.$value,
      extensions: node.$extensions || {},
    });
    return list;
  }

  for (const [key, child] of Object.entries(node)) {
    if (key.startsWith("$")) continue;
    collectTokens(child, [...pathSegments, key], list);
  }

  return list;
}

function parseWebVar(webSyntax) {
  if (!webSyntax || typeof webSyntax !== "string") return null;
  const match = webSyntax.match(/var\((--[^)]+)\)/);
  if (match) return match[1];
  if (webSyntax.startsWith("--")) return webSyntax;
  return null;
}

function isBreakpointToken(segments) {
  return String(segments[0] || "").toLowerCase() === "breakpoint";
}

function isContainerToken(segments) {
  return String(segments[0] || "").toLowerCase() === "container";
}

function formatPx(value) {
  if (typeof value === "number") return `${value}px`;
  return value;
}

function formatRemValue(rem) {
  const rounded = Math.round(rem * 10000) / 10000;
  return `${rounded}rem`;
}

function formatLength(value) {
  if (typeof value === "number") return formatRemValue(value / 16);
  if (typeof value === "string") {
    const trimmed = value.trim();
    if (trimmed.endsWith("px")) {
      const parsed = Number.parseFloat(trimmed.slice(0, -2));
      if (!Number.isNaN(parsed)) return formatRemValue(parsed / 16);
    }
    return trimmed;
  }
  return value;
}

function formatColor(rawValue) {
  if (!rawValue || typeof rawValue !== "object") return rawValue;
  const { components, alpha, hex } = rawValue;
  if (hex && (alpha === 1 || alpha === undefined)) return hex;
  if (Array.isArray(components) && components.length >= 3) {
    const [r, g, b] = components.map((c) => Math.round(c * 255));
    const a = alpha === undefined ? 1 : alpha;
    return `rgba(${r} ${g} ${b} / ${a})`;
  }
  return rawValue;
}

function resolveAliasString(value, webVarByPath) {
  if (typeof value !== "string") return value;
  const trimmed = value.trim();
  if (!trimmed.startsWith("{") || !trimmed.endsWith("}")) return value;
  const inner = trimmed.slice(1, -1).trim();
  const pathKey = inner.replace(/\./g, "/");
  const webVar = webVarByPath.get(pathKey);
  return webVar ? `var(${webVar})` : value;
}

function formatTokenValue(token, webVarByPath) {
  const type = String(token.type || "").toLowerCase();
  const rawValue = token.value;

  if (type === "color") return formatColor(rawValue);
  if (type === "number") {
    if (isBreakpointToken(token.pathSegments) || isContainerToken(token.pathSegments)) {
      return formatPx(rawValue);
    }
    return formatLength(rawValue);
  }

  const aliasResolved = resolveAliasString(rawValue, webVarByPath);
  if (aliasResolved !== rawValue) return aliasResolved;

  if (typeof rawValue === "string") return rawValue;
  if (rawValue && typeof rawValue === "object") return JSON.stringify(rawValue);
  return rawValue;
}

function buildCss(vars) {
  const lines = vars.map(({ name, value }) => `  ${name}: ${value};`);
  return [
    "@layer tokens {",
    "  :root {",
    ...lines,
    "  }",
    "}",
    "",
  ].join("\n");
}

async function run() {
  const files = await fg(EXPORT_PATTERNS, {
    cwd: REPO_ROOT,
    absolute: true,
    onlyFiles: true,
    unique: true,
  });

  if (files.length === 0) {
    throw new Error(`No token exports found in ${EXPORTS_DIR}`);
  }

  if (!fs.existsSync(OUTPUT_DIR)) {
    fs.mkdirSync(OUTPUT_DIR, { recursive: true });
  }

  for (const filePath of files.sort()) {
    const data = readJsonLike(filePath);
    const tokens = collectTokens(data);
    const webVarByPath = new Map();

    for (const token of tokens) {
      const web = token.extensions?.["com.figma.codeSyntax"]?.WEB;
      const varName = parseWebVar(web);
      if (!varName) continue;
      webVarByPath.set(token.pathSegments.join("/"), varName);
    }

    const vars = [];
    for (const token of tokens) {
      const web = token.extensions?.["com.figma.codeSyntax"]?.WEB;
      const varName = parseWebVar(web);
      if (!varName) continue;
      const value = formatTokenValue(token, webVarByPath);
      if (value === undefined || value === null) continue;
      vars.push({ name: varName, value });
    }

    const rawBase = normalizeOutputBase(filePath);
    const base = normalizePerFileBase(rawBase);
    const outPath = path.join(OUTPUT_DIR, `${base}.css`);
    fs.writeFileSync(outPath, buildCss(vars));
  }

  console.log("✅ Minimal tokens generated using com.figma.codeSyntax.WEB");
  console.log(`📁 Files created in ${path.relative(REPO_ROOT, OUTPUT_DIR)}/`);
}

run().catch((error) => {
  console.error("❌ Error extracting tokens:", error.message);
  process.exit(1);
});
